const functions = require('firebase-functions');
const admin = require('firebase-admin');
admin.initializeApp();

exports.archiveVerifiedDeliveryImage = functions.database.ref('/deliveries/{deliveryId}')
    .onUpdate(async (change, context) => {
        const before = change.before.val();
        const after = change.after.val();

        // Check if the status just changed to 'verified'
        if (before.status !== 'verified' && after.status === 'verified') {
            const bucket = admin.storage().bucket();
            const originalFilePath = after.imagePath; // e.g., 'deliveries/image123.jpg'

            // Skip if it's already in the archive
            if (!originalFilePath || originalFilePath.startsWith('archive/')) {
                return null;
            }

            const fileName = originalFilePath.split('/').pop();
            const archiveFilePath = `archive/${after.driverEmail}/${fileName}`;

            try {
                // Move the file in Google Cloud Storage
                const file = bucket.file(originalFilePath);
                await file.move(archiveFilePath);

                console.log(`Successfully moved ${fileName} to archive.`);

                // Update the database with the new archived path
                return change.after.ref.update({
                    imagePath: archiveFilePath
                });

            } catch (error) {
                console.error("Error moving file to archive:", error);
                return null;
            }
        }
        return null;
    });
